#!/usr/bin/env python3
"""
apply_v322s_missed_eod_boot_sweep.py  (SentCom v322s)

Idempotent applier for the ACMR 2026-05-29 weekend-carry fix.

ROOT CAUSE (proven via diag_eod_flatten_escape --trade-id e11450ca):
  A close_at_eod position filled 15:38 ET Friday; the backend went DOWN
  before the 15:45 EOD pass (zero heartbeats, no eod_auto_close event on
  05-29) -> position carried the WEEKEND on its GTC stop -> gapped through
  it at Monday's open (-$285). Plus: BotTrade.created_at defaulted to ""
  so the row was invisible to every date-windowed query.

WHAT IT DOES
  services/trading_bot_service.py
    - BotTrade.created_at default "" -> default_factory now-ISO.
    - Schedules _missed_eod_boot_sweep_task at boot (sleep 75s, then
      re-checks every 2 min until the open when boots land premarket).
  services/position_manager.py
    - New PositionManager.missed_eod_boot_sweep(bot): tracked OPEN trade +
      policy close_at_eod=True + fill date is a PREVIOUS ET session ->
      CRITICAL alarm + state_integrity_event (missed_eod_carryover), then
      flatten NOW (market open) or report waiting_for_open (flattens at
      the bell). Alarm dedupe per trade per boot.
      Kill switch: MISSED_EOD_BOOT_SWEEP_ENABLED=0.
  NEW tests/test_v322s_missed_eod_boot_sweep.py (11 tests)
  NEW scripts/repair_created_at_backfill.py (dry-run by default; --apply
      backfills created_at from executed_at/pre_submit_at/closed_at)

SAFETY
  - Idempotent: no-op when v322s markers already exist.
  - Refuses to write unless ALL hunks match exactly once.
  - Timestamped .bak + py_compile validation with auto-restore.

USAGE
  cd ~/Trading-and-Analysis-Platform
  .venv/bin/python apply_v322s.py --dry-run
  .venv/bin/python apply_v322s.py
  .venv/bin/python -m pytest backend/tests/test_v322s_missed_eod_boot_sweep.py -q
  .venv/bin/python backend/scripts/repair_created_at_backfill.py          # dry-run
  .venv/bin/python backend/scripts/repair_created_at_backfill.py --apply  # then write

AFTER APPLYING (CRITICAL — StartTrading.bat runs `git checkout -- .`):
  git add backend/ && git commit -m "v322s: missed-EOD boot sweep + created_at fix" && git push origin main
  # THEN restart the backend.
"""
import argparse
import base64
import os
import py_compile
import shutil
import sys
import time

MARKER = "v322s"

HUNKS = [
    ('services/trading_bot_service.py', 'services/trading_bot_service.py hunk 1 (lines ~866-872)',
     '',
     ''),
    ('services/trading_bot_service.py', 'services/trading_bot_service.py hunk 2 (lines ~3885-3890)',
     '',
     ''),
    ('services/position_manager.py', 'services/position_manager.py hunk 1 (lines ~1182-1187)',
     'ICAgICAgICBleGNlcHQgRXhjZXB0aW9uIGFzIGU6CiAgICAgICAgICAgIGxvZ2dlci5lcnJvcihmIlt2MTkuMzQuMTcxIFNDQUxQLURFQ0FZXSBzd2VlcCBmYWlsZWQ6IHtlfSIpCgoKCiAgICBhc3luYyBkZWYgX2VvZF9uYWtlZF9mbGF0dGVuX2d1YXJkKHNlbGYsIGJvdDogJ1RyYWRpbmdCb3RTZXJ2aWNlJykgLT4gZGljdDoK',
     ''),
]

NEW_FILES = [
    ('tests/test_v322s_missed_eod_boot_sweep.py',
     ''),
    ('scripts/repair_created_at_backfill.py',
     ''),
]


def _d(s):
    return base64.b64decode(s).decode("utf-8")


def log(m):
    print(f"[v322s-applier] {m}", flush=True)


def find_repo(explicit):
    if explicit:
        return explicit
    here = os.path.abspath(os.path.dirname(__file__))
    for base in (here, os.getcwd(), os.path.expanduser("~/Trading-and-Analysis-Platform")):
        cur = base
        for _ in range(6):
            if os.path.isfile(os.path.join(cur, "backend", "services", "position_manager.py")):
                return cur
            parent = os.path.dirname(cur)
            if parent == cur:
                break
            cur = parent
    return None


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--repo", default=None)
    ap.add_argument("--dry-run", action="store_true")
    args = ap.parse_args()
    repo = find_repo(args.repo)
    if not repo:
        log("FATAL: repo not found (use --repo)")
        sys.exit(1)
    log(f"repo: {repo}")

    by_file = {}
    for rel, label, old_b64, new_b64 in HUNKS:
        by_file.setdefault(rel, []).append((label, _d(old_b64), _d(new_b64)))

    plans = []
    for rel, hunks in by_file.items():
        path = os.path.join(repo, "backend", rel)
        if not os.path.isfile(path):
            log(f"FATAL: missing {path}")
            sys.exit(1)
        src = open(path, encoding="utf-8").read()
        if MARKER in src:
            log(f"SKIP (already applied): {rel}")
            continue
        new_src = src
        for label, old, new in hunks:
            cnt = new_src.count(old)
            if cnt != 1:
                log(f"FATAL: {label} matched {cnt}x (expected 1). File drifted — do NOT apply.")
                sys.exit(1)
            new_src = new_src.replace(old, new, 1)
            log(f"  ok: {label}")
        plans.append((path, new_src))

    new_file_plans = []
    for rel, b64 in NEW_FILES:
        path = os.path.join(repo, "backend", rel)
        content = _d(b64)
        if os.path.isfile(path) and open(path, encoding="utf-8").read() == content:
            log(f"SKIP new file (identical): {rel}")
            continue
        new_file_plans.append((path, content))
        log(f"  will create: {rel}")

    if args.dry_run:
        log(f"DRY-RUN OK — {len(plans)} file(s) to patch, {len(new_file_plans)} to create.")
        return

    stamp = time.strftime("%Y%m%d_%H%M%S")
    backups = []
    for path, new_src in plans:
        bak = f"{path}.{stamp}.bak"
        shutil.copy2(path, bak)
        backups.append((path, bak))
        with open(path, "w", encoding="utf-8") as f:
            f.write(new_src)
        log(f"patched: {path} (backup: {os.path.basename(bak)})")
    for path, content in new_file_plans:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)
        log(f"created: {path}")

    failed = False
    for path, _ in plans + [(p, None) for p, _ in new_file_plans]:
        if not path.endswith(".py"):
            continue
        try:
            py_compile.compile(path, doraise=True)
        except Exception as e:
            log(f"COMPILE FAIL: {path}: {e}")
            failed = True
    if failed:
        for path, bak in backups:
            shutil.copy2(bak, path)
        log("RESTORED all backups. Nothing applied.")
        sys.exit(1)

    log("SUCCESS. Now: tests -> repair dry-run -> git commit/push BEFORE restarting:")
    log("  .venv/bin/python -m pytest backend/tests/test_v322s_missed_eod_boot_sweep.py -q")
    log("  .venv/bin/python backend/scripts/repair_created_at_backfill.py")
    log('  git add backend/ && git commit -m "v322s: missed-EOD boot sweep + created_at fix" && git push origin main')


if __name__ == "__main__":
    main()
